+/// Try to fold (icmp ult/ule X, C1) & (icmp eq (X & M), C2).
+/// If (X & M) == C2 implies X < C1 (or X <= C1), we can simplify to just (icmp eq (X & M), C2).
+/// For example: (icmp ult X, 5) & (icmp eq (X & -2), 2) -> (icmp eq (X & -2), 2)
+/// Try to fold (icmp ult/ule X, C1) & (icmp eq (X & M), C2).
+/// If (X & M) == C2 implies X < C1 (or X <= C1), we can simplify to just (icmp eq (X & M), C2).
+/// For example: (icmp ult X, 5) & (icmp eq (X & -2), 2) -> (icmp eq (X & -2), 2)
+/// Also handles signed comparisons: (icmp sgt X, 127) & (icmp eq (X & -32), 128) -> (icmp eq (X & -32), 128)
+static Value *foldAndOfRangeAndMaskedICmp(ICmpInst *LHS, ICmpInst *RHS,
+                                          InstCombiner::BuilderTy &Builder) {
+  // Match (icmp ult/ule/slt/sgt X, C1) & (icmp eq (X & M), C2)
+  Value *X1, *X2;
+  const APInt *C1, *C2, *Mask;
+  ICmpInst::Predicate PredL = LHS->getPredicate();
+  
+  // Check if LHS is a range comparison against a constant
+  if (!match(LHS->getOperand(1), m_APInt(C1)))
+    return nullptr;
+  
+  // Check if RHS is an equality comparison with a masked value
+  if (RHS->getPredicate() != ICmpInst::ICMP_EQ)
+    return nullptr;
+  if (!match(RHS->getOperand(1), m_APInt(C2)))
+    return nullptr;
+  if (!match(RHS->getOperand(0), m_And(m_Value(X2), m_APInt(Mask))))
+    return nullptr;
+  
+  // Get the value being compared in LHS
+  X1 = LHS->getOperand(0);
+  
+  // Both comparisons must be on the same value
+  if (X1 != X2)
+    return nullptr;
+  
+  // For (X & M) == C2 to be satisfiable, C2 must have 0s where M has 0s
+  // i.e., C2 & ~M == 0
+  APInt NotMask = ~*Mask;
+  if ((NotMask & *C2) != 0)
+    return nullptr;  // RHS is always false, the whole expression is false
+                     // (could fold to false, but let's be conservative)
+  
+  // Compute the min/max values X can take when (X & M) == C2
+  // MinX = C2 (all bits not in M are 0)
+  // MaxX = C2 | ~M (all bits not in M are 1)
+  APInt MinX = *C2;
+  APInt MaxX = *C2 | NotMask;
+  
+  // Check if the range check is implied by the masked equality
+  bool Implies = false;
+  switch (PredL) {
+  case ICmpInst::ICMP_ULT:
+    Implies = MaxX.ult(*C1);
+    break;
+  case ICmpInst::ICMP_ULE:
+    Implies = MaxX.ule(*C1);
+    break;
+  case ICmpInst::ICMP_SLT:
+    // For signed less-than, check if max value is less than C1
+    Implies = MaxX.slt(*C1);
+    break;
+  case ICmpInst::ICMP_SLE:
+    Implies = MaxX.sle(*C1);
+    break;
+  case ICmpInst::ICMP_SGT:
+    // For signed greater-than, check if min value is greater than C1
+    Implies = MinX.sgt(*C1);
+    break;
+  case ICmpInst::ICMP_SGE:
+    Implies = MinX.sge(*C1);
+    break;
+  case ICmpInst::ICMP_UGT:
+    // For unsigned greater-than, check if min value is greater than C1
+    Implies = MinX.ugt(*C1);
+    break;
+  case ICmpInst::ICMP_UGE:
+    Implies = MinX.uge(*C1);
+    break;
+  default:
+    return nullptr;
+  }
+  
+  if (Implies) {
+    // (X < C1) or (X > C1) is always true when (X & M) == C2
+    // Simplify to just RHS
+    return RHS;
+  }
+  
+  return nullptr;
+}
+
 /// Fold (icmp Pred1 V1, C1) & (icmp Pred2 V2, C2)
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
@@ -3489,6 +3578,15 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
             foldAndOrOfICmpsWithPow2AndWithZero(Builder, LHS, RHS, IsAnd, Q))
       return V;

+  // Try to fold (icmp ult/ule X, C) & (icmp eq (X & M), C2) -> (icmp eq (X & M), C2)
+  // when the masked equality implies the range check.
+  if (IsAnd && !IsLogical) {
+    if (Value *V = foldAndOfRangeAndMaskedICmp(LHS, RHS, Builder))
+      return V;
+    if (Value *V = foldAndOfRangeAndMaskedICmp(RHS, LHS, Builder))
+      return V;
+  }
+
   // This only handles icmp of constants: (icmp1 A, C1) | (icmp2 B, C2).
   if (!LHSC || !RHSC)
     return nullptr;
@@ -3609,10 +3707,34 @@ Value *InstCombinerImpl::foldBooleanAndOr(Value *LHS, Value *RHS,

   if (Value *Res = foldEqOfParts(LHS, RHS, IsAnd))
     return Res;
+  // Handle select pattern: select i1 (icmp Pred X, C1), i1 (icmp eq (X & M), C2), i1 false
+  // This is equivalent to: (icmp Pred X, C1) & (icmp eq (X & M), C2)
+  if (IsAnd) {
+    if (auto *LHSCmp = dyn_cast<ICmpInst>(LHS)) {
+      if (auto *Sel = dyn_cast<SelectInst>(RHS)) {
+        if (Sel->getCondition() == LHS && match(Sel->getFalseValue(), m_Zero())) {
+          if (auto *RHSCmp = dyn_cast<ICmpInst>(Sel->getTrueValue())) {
+            if (Value *Res = foldAndOfRangeAndMaskedICmp(LHSCmp, RHSCmp, Builder))
+              return Res;
+          }
+        }
+      }
+    }
+    // Also try the other direction: select i1 (icmp eq (X & M), C2), i1 (icmp Pred X, C1), i1 false
+    if (auto *RHSCmp = dyn_cast<ICmpInst>(RHS)) {
+      if (auto *Sel = dyn_cast<SelectInst>(LHS)) {
+        if (Sel->getCondition() == RHS && match(Sel->getFalseValue(), m_Zero())) {
+          if (auto *LHSCmp = dyn_cast<ICmpInst>(Sel->getTrueValue())) {
+            if (Value *Res = foldAndOfRangeAndMaskedICmp(LHSCmp, RHSCmp, Builder))
+              return Res;
+          }
+        }
+      }
+    }
+  }

   return nullptr;
 }
